  'ganzhou/house': ('Nhà thổ lâu Khách Gia', 'Văn hóa Khách Gia đã tồn tại hàng thế kỷ trong những ngôi nhà pháo đài hình tròn độc đáo.'),
  'ganzhou/pavilion': ('Úc Cô Đình', 'Từng được các thi sĩ thời Tống ca ngợi, đình đài này có tầm nhìn bao quát nơi hợp lưu của dòng sông.'),
  'ganzhou/star': ('Vạn lý Trường chinh', 'Cuộc Vạn lý Trường chinh của Hồng quân đã bắt đầu từ chính thành phố này.'),
  'putian/shrine': ('Đền thờ Mẫu Tổ', 'Nữ thần Mẫu Tổ, vị thần bảo hộ ngư dân, đã sinh ra tại đây và ngôi đền thờ chính của bà tọa lạc trên đảo Mi Châu.'),
  'putian/lychee': ('Vườn vải', 'Những cây vải nghìn năm tuổi đã mang lại cho thành phố này danh xưng \'xứ sở vải thiều\'.'),
  'putian/shoe': ('Thủ phủ giày dép', 'Một phần lớn sản lượng giày thể thao trên thế giới được sản xuất tại các xưởng ở thành phố này.'),
  'putian/wave': ('Đảo Mi Châu', 'Hòn đảo này nổi tiếng với những bãi biển thơ mộng và các lễ hội đền chùa đặc sắc, có thể đến đây bằng phà.'),
  'mudanjiang/snow': ('Làng Tuyết', 'Ngôi làng cổ tích này được bao phủ bởi những lớp tuyết dày, tỏa sáng rực rỡ trong mùa đông.'),
  'mudanjiang/lake': ('Hồ Kính Bạc', 'Đây là một hồ nước hình thành từ núi lửa, nơi có thác nước Điếu Thủy Lâu vẫn chảy mạnh mẽ ngay cả trong mùa đông.'),
  'mudanjiang/tiger': ('Công viên Hổ Siberia', 'Đây là một trong những khu bảo tồn hổ Siberia lớn nhất trên thế giới.'),
  'mudanjiang/ski': ('Mùa trượt tuyết', 'Mùa đông dài với tuyết phủ dày đặc đã đưa khu vực này trở thành điểm đến không thể bỏ qua của những người yêu trượt tuyết.'),
  'changzhou/dino': ('Công viên Khủng long', 'Công viên chủ đề về khủng long nổi tiếng nhất Trung Quốc này là biểu tượng du lịch gia đình của thành phố.'),
  'changzhou/pagoda': ('Chùa Thiên Ninh', 'Với chiều cao 153 mét, đây là ngôi chùa cao nhất thế giới nằm ngay trung tâm thành phố.'),
  'changzhou/comb': ('Nghề làm lược', 'Những chiếc lược Thường Châu với lịch sử ngàn năm từng là món quà quý giá được dâng lên cung đình.'),
  'changzhou/canal': ('Đại Vận Hà', 'Dọc theo bờ kênh là nơi lý tưởng để tản bộ, ngắm nhìn những khu phố cổ và ánh đèn đêm lung linh.'),
  'shaoxing/wine': ('Rượu Thiệu Hưng', 'Loại rượu gạo vàng trứ danh dùng trong ẩm thực Trung Hoa này đã được ủ tại đây hàng ngàn năm qua.'),
  'shaoxing/bridge': ('Cầu đá cổ', 'Thiệu Hưng với hệ thống kênh rạch chằng chịt vẫn còn lưu giữ hàng trăm cây cầu đá vòm cổ kính.'),
  'shaoxing/pen': ('Cái nôi thư pháp', 'Lan Đình của đại thư pháp gia Vương Hy Chi được coi là thánh địa của nghệ thuật thư pháp.'),
  'shaoxing/boat': ('Thuyền Ô Bồng', 'Những chiếc thuyền Ô Bồng được chèo bằng chân là phương tiện di chuyển cổ điển trên các con kênh ở đây.'),
  'bengbu/shell': ('Cảng Ngọc Trai', 'Tên gọi của thành phố có nghĩa là \'bến hàu\', nơi từng nổi tiếng với những viên ngọc trai quý giá từ sông Hoài.'),
  'bengbu/train': ('Cửa ngõ đường sắt', 'Thành phố này phát triển mạnh mẽ nhờ vị trí là điểm giao cắt quan trọng của tuyến đường sắt Bắc-Nam qua sông Hoài.'),
  'bengbu/river': ('Sông Hoài', 'Đây là dòng sông đóng vai trò là ranh giới tự nhiên phân chia miền Bắc và miền Nam Trung Quốc.'),
  'bengbu/blossom': ('Lễ hội hoa xuân', 'Mỗi độ xuân về, các công viên ven sông lại rực rỡ sắc hoa trong những lễ hội truyền thống.'),
  'jiujiang/mountain': ('Lư Sơn', 'Những đỉnh núi mờ sương của Lư Sơn, một di sản UNESCO, đã trở thành nguồn cảm hứng bất tận cho thi ca và hội họa.'),
  'jiujiang/tea': ('Trà Vân Vụ', 'Loại trà Vân Vụ trồng trên sườn núi Lư Sơn được mệnh danh là một trong những loại trà tinh tế nhất Trung Quốc.'),
  'jiujiang/lake': ('Hồ Bà Dương', 'Hồ nước ngọt lớn nhất Trung Quốc này là nơi trú ngụ của hàng ngàn con sếu vào mỗi mùa đông.'),
  'jiujiang/scroll': ('Thành phố thi ca', 'Cửa ngõ ven sông này từng là nơi lưu dấu những vần thơ bất hủ của Bạch Cư Dị và Tô Thức.'),
  'quanzhou/ship': ('Con đường tơ lụa trên biển', 'Từng được Marco Polo gọi là \'Zayton\', đây là cảng biển lớn nhất thế giới thời trung cổ và hiện là di sản UNESCO.'),
  'quanzhou/mosque': ('Thánh đường Thanh Tịnh', 'Được xây dựng từ năm 1009, đây là một trong những thánh đường Hồi giáo bằng đá cổ xưa nhất tại Trung Quốc.'),
  'quanzhou/puppet': ('Múa rối dây', 'Nghệ thuật múa rối dây Tuyền Châu là một truyền thống sân khấu có lịch sử hàng ngàn năm.'),
  'quanzhou/tea': ('Trà Thiết Quan Âm', 'Loại trà ô long trứ danh từ vùng An Khê lân cận được thế giới biết đến với cái tên \'Nữ thần sắt\'.'),
  'shanghai/pearl': ('Tháp Minh Châu Phương Đông', 'Với những quả cầu màu hồng vươn cao bên dòng Hoàng Phố, tòa tháp này là biểu tượng của một Thượng Hải hiện đại.'),
  'shanghai/bund': ('Bến Thượng Hải', 'Dãy kiến trúc lịch sử dọc bờ sông phản chiếu vẻ đẹp tráng lệ của Thượng Hải thời xưa.'),
  'shanghai/garden': ('Dự Viên', 'Khu vườn cổ thời nhà Minh với những hòn non bộ và hồ nước tạo nên một ốc đảo yên bình giữa lòng thành phố.'),
  'shanghai/xlb': ('Tiểu long bao', 'Những chiếc bánh bao hấp chứa đầy nước súp nóng hổi là món ăn sáng tinh túy của người Thượng Hải.'),
  'hangzhou/lake': ('Tây Hồ', 'Với những hàng liễu rủ, đảo nhỏ và cầu vòm, đây là hồ nước được ca ngợi nhiều nhất trong thi ca Trung Hoa.'),
  'hangzhou/tea': ('Trà Long Tỉnh', 'Được trồng trên các sườn đồi quanh hồ, loại trà xanh \'Giếng Rồng\' này là danh trà nổi tiếng nhất Trung Quốc.'),
  'hangzhou/temple': ('Chùa Linh Ẩn', 'Ngôi chùa 1.700 năm tuổi này nổi tiếng với các tác phẩm điêu khắc đá tinh xảo và tượng Phật khổng lồ.'),
  'hangzhou/silk': ('Phố lụa Hàng Châu', 'Lụa Hàng Châu đã có lịch sử dệt may hàng ngàn năm, từng là nguồn thịnh vượng ở điểm cuối phía đông của Con đường Tơ lụa.'),
  'chongqing/hongya': ('Hồng Nhai Động', 'Khu phức hợp nhà sàn bám vào vách đá này tỏa sáng rực rỡ như một tòa lâu đài cổ tích bên bờ sông khi đêm về.'),
  'chongqing/hotpot': ('Lẩu Trùng Khánh', 'Với hương vị cay nồng từ dầu ớt và tê từ hạt tiêu, lẩu chính là linh hồn ẩm thực của thành phố núi này.'),
  'chongqing/monorail': ('Đường sắt trên cao Trùng Khánh', 'Hình ảnh đoàn tàu chạy xuyên qua tòa nhà chung cư là biểu tượng độc đáo của thành phố địa hình đồi núi này.'),
  'chongqing/river': ('Tam Hiệp Trường Giang', 'Các chuyến du thuyền Tam Hiệp khởi hành từ cảng này, nơi thành phố vươn mình tại điểm giao thoa của hai dòng sông lớn.'),
  'dalian/square': ('Quảng trường Tinh Hải', 'Đây là quảng trường thành phố lớn nhất châu Á, nơi diễn ra nhiều lễ hội và sự kiện sôi động bên bờ biển.'),
  'dalian/beach': ('Bãi biển Đại Liên', 'Với những vịnh đá và mùa hè mát mẻ, Đại Liên là điểm nghỉ dưỡng ven biển được yêu thích nhất ở miền Bắc Trung Quốc.'),
  'dalian/football': ('Thành phố bóng đá', 'Được mệnh danh là \'cái nôi của bóng đá Trung Quốc\', đây là nơi sản sinh ra những câu lạc bộ giàu thành tích nhất cả nước.'),
  'dalian/seafood': ('Hải sản Đại Liên', 'Các loại hải sản từ vùng biển Hoàng Hải lạnh giá như sò điệp, tôm và nhím biển luôn là món ngon đặc trưng trên bàn tiệc nơi đây.'),
  'shenyang/palace': ('Thẩm Dương Cố Cung', 'Đây là cung điện đầu tiên của nhà Thanh, được xem như người anh em nhỏ hơn của Tử Cấm Thành ở Bắc Kinh.'),
  'shenyang/tomb': ('Lăng mộ nhà Thanh', 'Các khu lăng mộ phía Đông và phía Bắc bao quanh thành phố là những công trình tưởng niệm hoành tráng của các vị vua khai quốc nhà Thanh.'),
  'shenyang/factory': ('Cái nôi công nghiệp', 'Nơi đây là cái nôi của ngành công nghiệp nặng Trung Quốc, với những nhà máy khổng lồ từng giúp thành phố được gọi là \'vùng Ruhr của phương Đông\'.'),
  'shenyang/dumpling': ('Sủi cảo Lão Biên', 'Món sủi cảo hấp Lão Biên với lịch sử hơn 200 năm là đặc sản trứ danh trên bàn tiệc phương Bắc.'),
  'hefei/judge': ('Bao Công Từ', 'Là quê hương của vị quan thanh liêm Bao Chửng, ngôi đền này chính là biểu tượng cho sự chính trực và công lý.'),
  'hefei/science': ('Thành phố Khoa học', 'Đây là trung tâm công nghệ quy tụ nhiều trường đại học và phòng thí nghiệm hàng đầu của Trung Quốc.'),
  'hefei/lake': ('Hồ Sào', 'Một trong năm hồ nước ngọt lớn nhất Trung Quốc, nổi tiếng với đặc sản cá trắng và cua.'),
  'hefei/cake': ('Bánh vừng Lư Châu', 'Món bánh vừng nhân ngọt này là thức quà truyền thống lâu đời của vùng đất Lư Châu xưa.'),
  'foshan/wingchun': ('Vịnh Xuân Quyền', 'Đây là cái nôi của võ thuật Vịnh Xuân, nơi khởi nguồn của những huyền thoại như Diệp Vấn và Lý Tiểu Long.'),
  'foshan/lion': ('Múa lân', 'Được mệnh danh là thủ phủ của múa lân phương Nam, nơi những chú lân rực rỡ sắc màu nhảy múa điêu luyện trên các cột cao.'),
  'foshan/ceramic': ('Gốm Thạch Loan', 'Những lò nung nghìn năm tuổi vẫn ngày đêm tạo nên các bức tượng gốm Thạch Loan đầy sống động.'),
  'foshan/opera': ('Kịch Quảng Đông', 'Đây là vùng đất đã nuôi dưỡng và phát triển loại hình nghệ thuật sân khấu được yêu thích nhất miền Nam Trung Quốc.'),
  'guiyang/pavilion': ('Giáp Tú Các', 'Tòa lầu ba tầng nằm trên sông Nam Minh này đã trở thành biểu tượng của thành phố suốt 400 năm qua.'),
  'guiyang/sourfish': ('Cá nấu canh chua', 'Món cá nấu trong nước dùng cà chua lên men có vị chua thanh đặc trưng là món ăn tiêu biểu của Quý Châu.'),
  'guiyang/waterfall': ('Thác Hoàng Quả Thụ', 'Một trong những thác nước lớn nhất châu Á đổ xuống ầm ầm, tạo nên những dải cầu vồng tuyệt đẹp.'),
  'guiyang/miao': ('Văn hóa người Miêu', 'Những lễ hội và nghề thêu thùa của người dân tộc Miêu với trang phục đội vương miện bạc đã làm bừng sáng các bản làng vùng cao.'),
  'changchun/film': ('Thành phố Điện ảnh', 'Nơi đây được mệnh danh là \'Hollywood của phương Đông\', cái nôi khai sinh ra nền điện ảnh Trung Quốc.'),
  'changchun/car': ('Thành phố Ô tô', 'Đây là thủ phủ ô tô của cả nước, nơi chiếc xe hơi đầu tiên do Trung Quốc tự sản xuất đã ra đời.'),
  'changchun/palace': ('Ngụy Mãn Hoàng cung', 'Cung điện nơi vị hoàng đế cuối cùng từng sinh sống là nhân chứng thầm lặng cho một giai đoạn lịch sử đầy biến động.'),
  'changchun/snow': ('Tuyết mùa đông', 'Suốt những mùa đông dài trắng xóa, thành phố bừng sáng với những tác phẩm điêu khắc băng và các đường trượt tuyết.'),
  'xining/lake': ('Hồ Thanh Hải', 'Hồ nước mặn lớn nhất Trung Quốc nổi tiếng với những cánh đồng hoa cải vàng rực rỡ bao quanh vào mùa hè.'),
  'xining/monastery': ('Tu viện Kumbum', 'Một trong sáu tu viện lớn nhất của Phật giáo Tây Tạng, nổi danh với các tác phẩm điêu khắc từ bơ bò yak.'),
  'xining/flower': ('Hoa cải dầu', 'Vào tháng Bảy, cả vùng cao nguyên như được phủ kín bởi những cánh đồng hoa cải vàng óng trải dài đến tận chân trời.'),
  'xining/lamb': ('Thịt bò yak và thịt cừu', 'Mì kéo tay và thịt cừu xiên nướng mang đậm phong vị ẩm thực Hồi giáo và Tây Tạng là linh hồn của vùng cao nguyên này.'),
  'guilin/karst': ('Núi đá vôi sông Ly', 'Những ngọn núi đá vôi nhô lên từ làn sương mờ ảo chính là khung cảnh được in trên tờ tiền 20 nhân dân tệ.'),
  'guilin/elephant': ('Núi Vòi Voi', 'Tảng đá có hình dáng như chú voi đang cúi vòi xuống dòng sông là biểu tượng yêu dấu của thành phố.'),
  'guilin/terrace': ('Ruộng bậc thang Long Tích', 'Những thửa ruộng bậc thang \'Sống lưng rồng\' uốn lượn trên sườn núi là minh chứng cho hàng thế kỷ lao động cần cù.'),
  'guilin/osmanthus': ('Hoa quế', 'Tên gọi của thành phố có nghĩa là \'rừng quế\', nơi mỗi độ thu về lại ngập tràn trong hương thơm ngọt ngào của loài hoa này.'),
  'wenzhou/merchant': ('Tinh thần thương nhân', 'Được mệnh danh là \'người Do Thái của Trung Quốc\', các doanh nhân Ôn Châu đã xây dựng mạng lưới kinh doanh trên khắp toàn cầu.'),
  'wenzhou/shoe': ('Giày da', 'Một phần lớn sản lượng giày da trên thế giới được sản xuất tại thành phố công nghiệp này.'),
  'wenzhou/mountain': ('Núi Nhạn Đãng', 'Nổi tiếng với những thác nước và đỉnh núi hiểm trở, nơi đây được ca ngợi là \'đệ nhất sơn bên bờ biển\'.'),
  'wenzhou/seafood': ('Hải sản', 'Mực, sò điệp và các loại cá từ biển Hoa Đông là nguyên liệu chủ đạo trong các bữa ăn của người dân địa phương.'),
  'tangshan/memorial': ('Đài tưởng niệm động đất', 'Công viên tưởng niệm trận động đất lịch sử năm 1976 là biểu tượng cho sự hồi sinh mạnh mẽ của thành phố.'),
  'tangshan/coal': ('Mỏ than Đường Sơn', 'Đây là cái nôi của ngành công nghiệp hiện đại Trung Quốc, nơi mở cửa mỏ than và tuyến đường sắt đầu tiên của cả nước.'),
  'tangshan/ceramic': ('Gốm sứ Đường Sơn', 'Được mệnh danh là \'thành phố gốm sứ phương Bắc\', các sản phẩm sứ xương tại đây nổi tiếng với vẻ đẹp tinh tế và sang trọng.'),
  'tangshan/lake': ('Công viên Nam Hồ', 'Từ một hố khai thác mỏ cũ, nơi đây đã được cải tạo thành công viên hồ nước, đóng vai trò như lá phổi xanh của thành phố.'),
  'anshan/steel': ('Thành phố Thép', 'Nơi đây là \'thủ phủ thép\' của Trung Quốc, đồng thời là địa điểm đặt nhà máy luyện thép lớn nhất cả nước.'),
  'anshan/jade': ('Ngọc Tú Nham', 'Thành phố này được coi là vùng đất ngọc của Trung Quốc, nơi lưu giữ tác phẩm điêu khắc bằng ngọc lớn nhất thế giới.'),
  'anshan/mountain': ('Núi Thiên Sơn', 'Với những ngôi chùa cổ và vách đá hùng vĩ, \'Thiên Sơn\' được coi là ngọn núi thiêng liêng bậc nhất vùng Đông Bắc.'),
  'anshan/spring': ('Suối khoáng Thang Cương Tử', 'Suối nước nóng này đã được các hoàng đế xưa ưa chuộng và nổi tiếng với công dụng chữa bệnh suốt hàng ngàn năm qua.'),
  'linyi/market': ('Chợ đầu mối Lâm Nghi', 'Đây là trung tâm bán buôn lớn nhất miền Bắc Trung Quốc, chuyên cung cấp hàng hóa đi khắp cả nước.'),
  'linyi/brush': ('Quê hương Thư pháp', 'Là nơi sinh của \'Thư thánh\' Vương Hi Chi, thành phố này được mệnh danh là vùng đất của mực và bút lông.'),
  'linyi/mountain': ('Núi Mông Sơn', 'Là ngọn núi cao thứ hai tỉnh Sơn Đông, nơi đây được ví như \'quán bar oxy\' với không khí trong lành và những thác nước tuyệt đẹp.'),
  'linyi/pancake': ('Bánh kếp Nghi Mông', 'Loại bánh kếp mỏng làm từ ngô này là món ăn truyền thống lâu đời của người dân vùng núi Nghi Mông.'),
  'cangzhou/lion': ('Sư tử sắt Thương Châu', 'Bức tượng sư tử bằng sắt khổng lồ có lịch sử hơn 1.100 năm này là biểu tượng đầy tự hào của thành phố.'),
  'cangzhou/martial': ('Võ thuật Thương Châu', 'Được mệnh danh là \'quê hương của võ thuật\', nơi đây là cái nôi sản sinh ra nhiều võ sư và các trường phái võ thuật nổi tiếng.'),
  'cangzhou/canal': ('Đại Vận Hà', 'Kênh đào Đại Vận Hà Bắc Kinh - Hàng Châu chảy qua thành phố, nơi vẫn còn lưu giữ những bến tàu cổ kính.'),
  'cangzhou/jujube': ('Táo tàu vàng', 'Loại táo tàu \'tơ vàng\' với lớp vỏ mỏng và vị ngọt thanh được mệnh danh là vua của các loại trái cây sấy khô.'),
  'nantong/textile': ('Thành phố Dệt may', 'Được mệnh danh là thủ phủ dệt may của Trung Quốc, các sản phẩm vải bông tại đây đã vươn tầm ra thị trường thế giới.'),
  'nantong/mountain': ('Núi Lang', 'Ngọn núi thiêng với năm đỉnh nhấp nhô nằm ngay cửa sông Dương Tử là điểm hành hương và ngắm cảnh nổi tiếng.'),
  'nantong/kite': ('Diều sáo', 'Những chiếc diều sáo \'banyao\' với âm thanh ngân vang là một loại hình thủ công truyền thống lâu đời của thành phố.'),
  'nantong/school': ('Cái nôi giáo dục', 'Nhà công nghiệp Trương Kiên đã thành lập bảo tàng và những ngôi trường hiện đại đầu tiên của Trung Quốc tại đây.'),
  'taizhou/opera': ('Mai Lan Phương', 'Đây là quê hương của Mai Lan Phương, bậc thầy huyền thoại của nghệ thuật Kinh kịch.'),
  'taizhou/tea': ('Trà sáng', 'Thưởng thức trà cùng bánh bao vào buổi sáng đã trở thành một nét văn hóa ẩm thực đặc trưng của người dân nơi đây.'),
  'taizhou/boat': ('Lễ hội đua thuyền Côn Thông', 'Vào mùa xuân, lễ hội với hàng trăm tay chèo tranh tài đã mang lại sức sống mãnh liệt cho dòng sông.'),
  'taizhou/meatball': ('Thịt viên đầu sư tử', 'Món thịt viên mềm mại, thơm ngon này là một tuyệt phẩm kinh điển của nền ẩm thực Hoài Dương.'),
  'jinhua/ham': ('Giăm bông Kim Hoa', 'Được chế biến bằng phương pháp truyền thống hàng thế kỷ, đây là loại giăm bông nổi tiếng nhất tại Trung Quốc.'),
  'jinhua/film': ('Phim trường Hoành Điếm', 'Đây là phim trường ngoài trời lớn nhất thế giới, nơi thực hiện vô số bộ phim cổ trang nổi tiếng.'),
  'jinhua/cave': ('Động Song Long', 'Du khách sẽ được trải nghiệm cảm giác choáng ngợp khi đi thuyền qua cửa hang đá thấp để tiến vào hang động ngầm kỳ vĩ.'),
  'jinhua/bridge': ('Cầu cổ', 'Những cây cầu đá vòm cùng các thị trấn ven sông mang đậm nét duyên dáng đặc trưng của vùng Giang Nam.'),
  'wuhu/park': ('Công viên giải trí Fangte', 'Là một trong những công viên chủ đề lớn nhất Trung Quốc, nơi đây mang đến cho các gia đình những ngày vui chơi đầy phấn khích.'),
  'wuhu/ironart': ('Tranh sắt', 'Những bức tranh sắt tinh xảo được rèn từ sắt uốn là một loại hình thủ công mỹ nghệ có lịch sử 300 năm.'),
  'wuhu/rice': ('Cảng gạo', 'Thành phố nằm bên bờ sông Dương Tử này từng là thị trường kinh doanh gạo lớn nhất Trung Quốc trong lịch sử.'),
  'wuhu/river': ('Cảng Dương Tử', 'Đây là cảng sông sầm uất, đóng vai trò như cửa ngõ thông ra biển của tỉnh An Huy.'),
  'huangshan/peak': ('Hoàng Sơn', 'Với những đỉnh núi đá granite, biển mây bồng bềnh và những cây thông cổ thụ, đây là ngọn núi nổi tiếng nhất Trung Quốc.'),
  'huangshan/village': ('Thôn Hoành', 'Ngôi làng cổ với những bức tường trắng soi bóng bên dòng nước này đã được UNESCO công nhận là di sản thế giới, đẹp tựa như một bức tranh thủy mặc.'),
  'huangshan/tea': ('Trà Mao Phong', 'Được hái trên những sườn núi mờ sương, loại trà xanh với những búp non phủ lông tơ này là một trong mười loại trà danh tiếng nhất Trung Quốc.'),
  'huangshan/ink': ('Mực và Nghệ thuật Huy Châu', 'Mực Huy Châu, những ngôi nhà gỗ chạm khắc tinh xảo và thư pháp chính là kho tàng văn hóa quý giá của vùng đất này.'),
  'yichun/moon': ('Núi Minh Nguyệt', 'Ngọn núi \'Trăng Sáng\' này nổi tiếng với các suối nước nóng và tầm nhìn tuyệt đẹp từ cáp treo.'),
  'yichun/spring': ('Suối nước nóng', 'Những dòng suối nước nóng giàu selen quý hiếm đã biến thành phố này thành trung tâm nghỉ dưỡng tắm khoáng của Trung Quốc.'),
  'yichun/zen': ('Thiền tông', 'Những ngôi chùa trên núi gắn liền với các tông phái Thiền tông Trung Hoa mời gọi du khách tìm về sự tĩnh lặng.'),
  'yichun/rice': ('Đồng bằng Viên-Hà', 'Vùng đồng bằng màu mỡ Viên-Hà từ lâu đã được coi là vựa lúa của tỉnh Giang Tây.'),
  'zhangzhou/narcissus': ('Hoa thủy tiên', 'Đây là nơi trồng hoa thủy tiên nổi tiếng nhất Trung Quốc, loài hoa biểu tượng cho các dịp lễ hội mùa xuân.'),
  'zhangzhou/tulou': ('Thổ lâu Khách Gia', 'Những pháo đài bằng đất nện hình tròn khổng lồ này được UNESCO công nhận là di sản, nơi cả một ngôi làng cùng chung sống dưới một mái nhà.'),
  'zhangzhou/banana': ('Trái cây nhiệt đới', 'Những vườn chuối, nhãn và quýt giúp vùng đồng bằng ấm áp này luôn xanh tươi quanh năm.'),
  'zhangzhou/coast': ('Đảo Đông Sơn', 'Với những bãi biển vàng và các làng chài yên bình, hòn đảo này được ví như viên ngọc quý của vùng duyên hải phía nam.'),
  'guangzhou/tower': ('Tháp Quảng Châu', 'Được mệnh danh là \'Eo thon\', đây là một trong những tòa tháp cao nhất thế giới, tỏa sáng rực rỡ với sắc màu thay đổi mỗi đêm.'),
  'guangzhou/dimsum': ('Trà sáng', 'Thưởng thức dim sum hấp trong những chiếc xửng tre cùng trà nóng là linh hồn trong văn hóa ẩm thực của người Quảng Đông.'),
  'guangzhou/academy': ('Từ đường dòng họ Trần', 'Nổi tiếng với các tác phẩm chạm khắc gỗ và phù điêu gốm sứ tinh xảo, đây là kiệt tác tiêu biểu cho nghệ thuật thủ công Quảng Đông.'),
  'guangzhou/flower': ('Thành phố Hoa', 'Với hoa nở quanh năm và các hội hoa xuân rực rỡ, Quảng Châu từ lâu đã được mệnh danh là \'Thành phố Hoa\'.'),
  'wuhan/crane': ('Hoàng Hạc Lâu', 'Tọa lạc bên dòng Trường Giang, tòa tháp nghìn năm tuổi này là nguồn cảm hứng cho những bài thơ nổi tiếng nhất Trung Quốc.'),
  'wuhan/noodle': ('Mì khô nóng', 'Mì khô nóng trộn sốt mè là món ăn sáng không thể thiếu của người dân Vũ Hán.'),
  'wuhan/duckneck': ('Cổ vịt cay', 'Cổ vịt om cay là món ăn vặt khoái khẩu của người dân địa phương trong những buổi trò chuyện đêm khuya.'),
  'wuhan/university': ('Hoa anh đào Đại học Vũ Hán', 'Mùa hoa anh đào tại Đại học Vũ Hán thu hút hàng nghìn du khách ghé thăm mỗi độ xuân về.'),
  'tianjin/eye': ('Mắt Thiên Tân', 'Đây là vòng quay mặt trời được xây dựng ngay trên cầu, cho phép du khách ngắm nhìn toàn cảnh hai bên bờ sông.'),
  'tianjin/baozi': ('Bánh bao Cẩu Bất Lý', 'Món bánh bao nhân thịt hấp với lớp vỏ xếp nếp tinh tế là đặc sản trứ danh có lịch sử 150 năm của thành phố.'),
  'tianjin/crosstalk': ('Tướng thanh', 'Tướng thanh là loại hình hài kịch đối đáp truyền thống của Thiên Tân, khởi nguồn từ các quán trà xưa.'),
  'tianjin/architecture': ('Khu phố châu Âu', 'Những biệt thự mang phong cách châu Âu tại Ngũ Đại Đạo đã giúp Thiên Tân được ví như một \'bảo tàng kiến trúc\'.'),
  'xiamen/island': ('Đảo Cổ Lãng Tự', 'Với những con đường không bóng xe cộ và các biệt thự cổ kính, hòn đảo được UNESCO công nhận này giống như một bảo tàng ngoài trời.'),
  'xiamen/piano': ('Đảo Dương cầm', 'Nhờ sở hữu số lượng đàn piano trên đầu người cao nhất cả nước, Cổ Lãng Tự còn được gọi là \'đảo dương cầm\'.'),
  'xiamen/egret': ('Cò trắng', 'Cò trắng là biểu tượng của thành phố, gợi nhắc về tên gọi cũ \'Lộ Đảo\' (đảo cò) của Hạ Môn.'),
  'xiamen/oyster': ('Trứng chiên hàu', 'Món trứng chiên hàu tươi giòn là ngôi sao sáng trong nền ẩm thực vùng duyên hải này.'),
  'harbin/ice': ('Lễ hội Băng đăng', 'Lễ hội mùa đông với những cung điện băng khổng lồ rực rỡ ánh đèn tại Cáp Nhĩ Tân là lễ hội lớn nhất thế giới.'),
  'harbin/cathedral': ('Nhà thờ Thánh Sophia', 'Nhà thờ Chính thống giáo Nga với mái vòm hình củ hành này là biểu tượng cho di sản châu Âu của thành phố.'),
  'harbin/sausage': ('Xúc xích đỏ', 'Món xúc xích đỏ hun khói kiểu Nga là đặc sản có lịch sử hàng trăm năm của thành phố này.'),
  'harbin/accordion': ('Thành phố âm nhạc', 'Với bề dày di sản văn hóa Nga, Cáp Nhĩ Tân là nơi thành lập dàn nhạc giao hưởng đầu tiên của Trung Quốc.'),
  'fuzhou/alley': ('Tam Phường Thất Ngõ', 'Khu phố cổ với tường trắng ngói đen này là một bảo tàng sống động về kiến trúc thời Minh - Thanh.'),
  'fuzhou/banyan': ('Thành phố cây đa', 'Những cây đa cổ thụ khổng lồ tỏa bóng mát khắp các con phố khiến Phúc Châu được mệnh danh là \'thành phố cây đa\'.'),
  'fuzhou/hotspring': ('Suối nước nóng', 'Các mạch nước nóng tự nhiên chảy ngay trong lòng thành phố đã phục vụ các nhà tắm công cộng suốt hàng ngàn năm qua.'),
  'fuzhou/soup': ('Phật nhảy tường', 'Được hầm từ hàng chục nguyên liệu quý, món súp xa xỉ này là kiệt tác của ẩm thực Phúc Kiến.'),
  'dongguan/robot': ('Công xưởng thế giới', 'Với các nhà máy tự động hóa hiện đại, Đông Quản là nơi sản xuất một phần lớn các thiết bị điện tử trên toàn cầu.'),
  'dongguan/basketball': ('Thành phố bóng rổ', 'Câu lạc bộ bóng rổ giàu thành tích nhất Trung Quốc đang thi đấu tại \'thành phố bóng rổ\' này.'),
  'dongguan/keyuan': ('Khả Viên', 'Đây là một trong bốn khu vườn cổ điển nổi tiếng nhất Quảng Đông, nổi tiếng với những hồ nước và đình đài tuyệt đẹp.'),
  'dongguan/cannon': ('Pháo đài Hổ Môn', 'Pháo đài Hổ Môn, nơi khởi đầu của Chiến tranh Nha phiến, đánh dấu bờ biển từng diễn ra sự kiện tiêu hủy thuốc phiện lịch sử.'),
  'lanzhou/beefnoodle': ('Mì bò Lan Châu', 'Với nước dùng bò trong vắt và sợi mì kéo tay đặc trưng, Lan Châu được coi là thủ phủ mì của Trung Quốc.'),
  'lanzhou/waterwheel': ('Guồng nước', 'Những chiếc guồng nước khổng lồ bên bờ sông Hoàng Hà tượng trưng cho kỹ thuật thủy lợi có từ nhiều thế kỷ trước.'),
  'lanzhou/statue': ('Tượng Mẹ Hoàng Hà', 'Bức tượng mẹ và con bên bờ sông khắc họa hình ảnh dòng sông đã nuôi dưỡng nền văn minh Trung Hoa.'),
  'lanzhou/raft': ('Bè da cừu', 'Những chiếc bè truyền thống làm từ da cừu thổi phồng vẫn đang trôi trên dòng sông Hoàng Hà.'),
  'urumqi/bazaar': ('Đại chợ Tân Cương', 'Với những tòa tháp cao vút và các quầy gia vị sực nức, khu chợ này mang đậm sắc màu của Con đường Tơ lụa.'),
  'urumqi/tianshan': ('Thiên Trì', 'Nằm dưới những đỉnh núi tuyết của dãy Thiên Sơn, hồ Thiên Trì được bao quanh bởi những cánh rừng vân sam xanh mướt.'),
  'urumqi/kebab': ('Thịt cừu xiên nướng', 'Những xiên thịt cừu tẩm gia vị nướng trên than hồng là món ăn không thể thiếu trên bàn tiệc của người Duy Ngô Nhĩ.'),
  'urumqi/dance': ('Điệu múa Duy Ngô Nhĩ', 'Những điệu múa xoay người uyển chuyển của người Duy Ngô Nhĩ trên nền nhạc trống và đàn rawap luôn làm bừng sáng mọi lễ hội.'),
  'haikou/coconut': ('Thành phố Dừa', 'Những con phố rợp bóng dừa đã mang lại cho Hải Khẩu biệt danh \'thành phố dừa\'.'),
  'haikou/arcade': ('Phố cổ Kỵ Lâu', 'Những tòa nhà \'kỵ lâu\' với hàng hiên có cột chống tạo nên những con phố có mái che đặc trưng của vùng đất phương Nam.'),
  'haikou/crater': ('Miệng núi lửa', 'Những miệng núi lửa đã tắt tạo nên một công viên địa chất xanh mát ngay bên rìa thành phố.'),
  'haikou/turtle': ('Biển nhiệt đới', 'Làn nước trong xanh ấm áp cùng những rạn san hô đã biến vùng biển này thành ngôi nhà của loài rùa biển.'),
  'luoyang/grotto': ('Hang đá Long Môn', 'Hàng chục ngàn bức tượng Phật được chạm khắc tinh xảo trên vách đá tạo nên một kho tàng nghệ thuật được UNESCO công nhận.'),
  'luoyang/peony': ('Thủ phủ hoa mẫu đơn', 'Hàng ngàn đóa mẫu đơn đua nhau khoe sắc mỗi độ tháng Tư đã biến Lạc Dương thành \'thủ phủ hoa mẫu đơn\'.'),
  'luoyang/whitehorse': ('Chùa Bạch Mã', 'Được xây dựng từ năm 68 sau Công nguyên, ngôi chùa này được coi là ngôi chùa Phật giáo đầu tiên của Trung Quốc.'),
  'luoyang/capital': ('Cố đô Lạc Dương', 'Từng là kinh đô của mười ba triều đại, Lạc Dương được xem là một trong những cái nôi của nền văn minh Trung Hoa.'),
  'shantou/gongfutea': ('Trà đạo Triều Sán', 'Được pha chế cầu kỳ trong những chén nhỏ, trà đạo Triều Sán là một nét nghệ thuật hiếu khách đặc sắc.'),
  'shantou/beefpot': ('Lẩu bò Triều Sán', 'Món lẩu bò Triều Sán nổi tiếng với những lát thịt bò tươi ngon được nhúng chín chỉ trong vài giây.'),
  'shantou/opera': ('Kịch Triều Châu', 'Loại hình kịch Triều Châu có lịch sử 600 năm nổi tiếng với những làn điệu tinh tế và trang phục thêu thùa lộng lẫy.'),
  'shantou/harbor': ('Thành phố cảng Sán Đầu', 'Là quê hương của nhiều người Hoa hải ngoại, cảng biển này từng là cửa ngõ giao thương hàng hải lâu đời.'),
  'baoding/mansion': ('Phủ Tổng đốc Trực Lệ', 'Đây là cơ quan hành chính cấp tỉnh được bảo tồn nguyên vẹn nhất từ thời nhà Thanh.'),
  'baoding/donkeyburger': ('Bánh kẹp thịt lừa', 'Thịt lừa tẩm ướp gia vị kẹp trong lớp vỏ bánh giòn tan là món ăn đường phố đặc trưng của vùng này.'),
  'baoding/balls': ('Bóng tập dưỡng sinh', 'Việc xoay những quả cầu kim loại trong lòng bàn tay là một phương pháp rèn luyện sức khỏe truyền thống có từ hàng thế kỷ trước.'),
  'baoding/reeds': ('Đầm lầy Bạch Dương Điến', 'Vùng đất ngập nước lớn nhất miền Bắc này là thiên đường của các loài chim với những cánh đồng lau sậy và hoa sen bát ngát.'),
  'jilin/rime': ('Băng giá Cát Lâm', 'Hiện tượng băng giá phủ trắng cây cối bên bờ sông Tùng Hoa là một trong bốn kỳ quan thiên nhiên của Trung Quốc.'),
  'jilin/snowboard': ('Khu nghỉ dưỡng trượt tuyết', 'Với lớp tuyết dày và mùa đông kéo dài, thành phố này là một trong những điểm trượt tuyết hàng đầu ở miền Bắc.'),
  'jilin/meteorite': ('Bảo tàng Thiên thạch', 'Nơi đây trưng bày khối thiên thạch đá lớn nhất thế giới, rơi xuống trái đất vào năm 1976.'),
  'jilin/skate': ('Sông Tùng Hoa đóng băng', 'Vào mùa đông, dòng sông Tùng Hoa đóng băng trở thành sân băng tự nhiên thu hút đông đảo người dân đến trượt băng và dạo chơi.'),
  'ordos/khan': ('Lăng mộ Thành Cát Tư Hãn', 'Ngôi lăng mộ tráng lệ tôn vinh vị anh hùng thảo nguyên Thành Cát Tư Hãn là trái tim của văn hóa Mông Cổ.'),
  'ordos/cashmere': ('Len Cashmere', 'Len Cashmere dệt từ lông dê Ordos đã đưa thành phố này vươn tầm ra ngành dệt may thế giới.'),
  'ordos/sanddune': ('Cồn cát hát', 'Những đồi cát khổng lồ phát ra âm thanh khi bạn trượt xuống là điểm dừng chân thú vị nhất tại sa mạc Khố Bố Tề.'),
  'ordos/yurt': ('Lều Yurt Mông Cổ', 'Những chiếc lều nỉ trắng dựng trên thảo nguyên bao la là biểu tượng cho cuộc sống du mục.'),
  'jining/confucius': ('Đền thờ Khổng Tử', 'Nằm ở Khúc Phụ gần đó, quần thể đền thờ, dinh thự và mộ phần của Khổng Tử đã được UNESCO công nhận là di sản thế giới.'),
  'jining/barge': ('Đại Vận Hà', 'Từng là một cảng thị sầm uất trên tuyến kênh đào Bắc Kinh - Hàng Châu, Tế Ninh là trung tâm quan trọng của văn hóa kênh đào.'),
  'jining/sword': ('Các anh hùng Lương Sơn', '108 vị anh hùng hảo hán trong tác phẩm kinh điển Thủy Hử đã tụ hội tại vùng đồi núi đầm lầy này.'),
  'jining/fishnet': ('Hồ Vi Sơn', 'Trên mặt hồ sen lớn nhất phương Bắc, ngư dân vẫn duy trì phương thức đánh bắt cá truyền thống từ bao đời nay.'),
  'langfang/culture': ('Trung tâm Văn hóa Con đường Tơ lụa', 'Trung tâm văn hóa hiện đại quy mô lớn này là nơi hội tụ các loại hình nghệ thuật đặc sắc dọc Con đường Tơ lụa.'),
  'langfang/furniture': ('Thành phố Nội thất', 'Hương Hà là một trong những trung tâm sản xuất và giao thương đồ nội thất lớn nhất tại Trung Quốc.'),
  'langfang/tunnel': ('Địa đạo Chiến tranh Cổ đại', 'Hệ thống địa đạo quân sự có lịch sử hàng nghìn năm này từng là tuyến phòng thủ biên giới quan trọng.'),
  'langfang/themepark': ('Công viên Đệ nhất Thành', 'Đây là một công viên chủ đề rộng lớn tái hiện lại khung cảnh của một thành trì cổ xưa, thu hút rất nhiều gia đình đến tham quan.'),
  'yancheng/salt': ('Diêm Thành', 'Tên gọi của thành phố có nghĩa là \'thành phố muối\', nơi từng là trung tâm sản xuất muối quan trọng của Trung Quốc trong nhiều thế kỷ.'),
  'yancheng/crane': ('Sếu đầu đỏ', 'Vùng đất ngập nước ven biển này là nơi trú đông lớn nhất thế giới của loài sếu đầu đỏ hoang dã.'),
  'yancheng/elk': ('Hươu Père David', 'Từng có nguy cơ tuyệt chủng trong tự nhiên, loài hươu Milu đã được nhân giống và phục hồi thành công tại các vùng đất ngập nước này.'),
  'yancheng/wetland': ('Đất ngập nước ven biển', 'Những bãi bồi ven biển được UNESCO công nhận là điểm dừng chân quan trọng trên hành trình di cư của các loài chim trên toàn cầu.'),
  'huzhou/brush': ('Bút Hồ', 'Bút Hồ, một trong \'văn phòng tứ bảo\' của nghệ thuật thư pháp Trung Hoa, được chế tác thủ công tại chính nơi này.'),
  'huzhou/bamboo': ('Trúc hải An Cát', 'Những rừng trúc xanh mướt trải dài vô tận không chỉ là nguồn cảm hứng cho điện ảnh mà còn giúp điều hòa không khí vô cùng mát mẻ.'),
  'huzhou/silkworm': ('Tằm dâu', 'Bờ nam hồ Thái Hồ từ lâu đã nổi tiếng là trung tâm sản xuất tơ lụa từ hàng nghìn năm nay.'),
  'huzhou/whitetea': ('Bạch trà An Cát', 'Với lá trà màu nhạt và hương vị ngọt dịu, bạch trà An Cát được xếp vào hàng những loại trà quý hiếm nhất Trung Quốc.'),
  'quzhou/go': ('Cờ vây', 'Gắn liền với truyền thuyết về núi Lạn Kha, thành phố này được tôn vinh là vùng đất thánh của bộ môn cờ vây.'),
  'quzhou/peaks': ('Núi Giang Lang', 'Ba cột đá khổng lồ vươn thẳng lên trời tạo nên một cảnh quan độc đáo được UNESCO công nhận.'),
  'quzhou/ponkan': ('Quýt đường Cù Châu', 'Loại quýt có lớp vỏ ngọt thanh này là món quà mùa đông đặc trưng của những ngọn đồi ôn hòa.'),
  'quzhou/cake': ('Bánh nướng Cù Châu', 'Bánh nướng mè giòn rụm được nướng trên thành lò là món ăn sáng truyền thống của người dân địa phương.'),
  'huainan/tofu': ('Cái nôi của đậu phụ', 'Được phát minh tại núi Bát Công cách đây 2.000 năm, đậu phụ từ đây đã lan tỏa ra nền ẩm thực thế giới.'),
  'huainan/coalmine': ('Thành phố than đá', 'Với trữ lượng than dồi dào, Hoài Nam là một trong những trung tâm năng lượng quan trọng của miền Đông Trung Quốc.'),
  'huainan/oldtown': ('Cổ thành Thọ Huyện', 'Tường thành từ thời nhà Tống được bảo tồn nguyên vẹn là ví dụ hiếm hoi về thiết kế phòng thủ cổ đại.'),
  'huainan/classic': ('Hoài Nam Tử', 'Tác phẩm triết học kinh điển do Hoài Nam Vương Lưu An biên soạn đã được ra đời trên mảnh đất này.'),
  'jingdezhen/porcelain': ('Thủ phủ gốm sứ', 'Với lịch sử sản xuất gốm sứ cung đình suốt ngàn năm, thành phố này được mệnh danh là \'thủ phủ gốm sứ\' của thế giới.'),
  'jingdezhen/kiln': ('Lò gốm cổ', 'Những lò nung hình rồng đốt bằng củi vẫn tiếp tục duy trì nghệ thuật làm gốm truyền thống cho đến ngày nay.'),
  'jingdezhen/bluewhite': ('Gốm sứ thanh hoa', 'Gốm sứ trắng với những họa tiết màu xanh coban là biểu tượng nổi tiếng thế giới của thành phố này.'),
  'jingdezhen/painting': ('Tranh vẽ trên gốm', 'Những tác phẩm gốm được các nghệ nhân bậc thầy vẽ bằng cọ tỉ mỉ được trân quý như những bức tranh nghệ thuật đích thực.'),
  'jian/jinggang': ('Núi Tỉnh Cương', 'Những ngọn núi mờ sương, nơi đặt căn cứ cách mạng đầu tiên, chính là trái tim của \'du lịch đỏ\'.'),
  'jian/torch': ('Ngọn lửa cách mạng', 'Mảnh đất khởi nguồn cho tư tưởng \'một đốm lửa có thể đốt cháy cả cánh đồng\' là một di tích lịch sử quan trọng.'),
  'jian/academy': ('Học viện Bạch Lộ Châu', 'Học viện nghìn năm tuổi nằm trên một hòn đảo giữa sông Cám là nơi đào tạo vô số học giả thời phong kiến.'),
  'jian/pine': ('Thông Tỉnh Cương', 'Những cây thông đỏ vươn mình trong sương mù tượng trưng cho tinh thần kiên cường của vùng núi này.'),
  'nanping/wuyi': ('Dãy núi Vũ Di', 'Được UNESCO công nhận là di sản thế giới, dãy núi này là sự kết hợp tuyệt vời giữa cảnh quan thiên nhiên hùng vĩ với những vách đá đỏ, khe suối xanh và các giá trị văn hóa lâu đời.'),
  'nanping/rocktea': ('Trà Vũ Di Nham', 'Đại Hồng Bào, một loại trà ô long nổi tiếng mọc trên các vách đá tại đây, được mệnh danh là một trong những loại trà đắt đỏ nhất thế giới.'),
  'nanping/bambooraft': ('Bè tre Cửu Khúc Khê', 'Du khách có thể trải nghiệm cảm giác ngồi trên những chiếc bè tre, thả mình trôi theo dòng suối Cửu Khúc uốn lượn giữa những vách đá đỏ kỳ vĩ.'),
  'nanping/scholar': ('Chu Hy', 'Chu Hy, nhà triết học lỗi lạc và là người sáng lập trường phái Tân Nho giáo, đã từng dành nhiều năm giảng dạy dưới chân dãy núi này.'),
  'beijing/great-wall': ('Vạn Lý Trường Thành', 'Đây là công trình phòng thủ quân sự dài nhất thế giới với hơn 20.000 km, trong đó đoạn Bát Đạt Lĩnh gần Bắc Kinh là nơi thu hút đông đảo du khách nhất nhờ những bậc thang đá và tháp canh cổ kính.'),
  'beijing/temple': ('Thiên Đàn', 'Đây là nơi các hoàng đế nhà Minh và nhà Thanh thực hiện nghi lễ tế trời cầu mưa thuận gió hòa, nổi tiếng với kiến trúc mái vòm ba tầng màu xanh được xây dựng hoàn toàn không dùng đến đinh.'),
  'beijing/pagoda': ('Chùa Thiên Ninh', 'Ngôi chùa gạch 13 tầng cao khoảng 57 mét từ thời nhà Liêu này là một trong những công trình kiến trúc cổ nhất còn sót lại tại Bắc Kinh, chứng kiến lịch sử ngàn năm của thành phố.'),
  'beijing/opera': ('Kinh kịch', 'Loại hình nghệ thuật truyền thống hơn 200 năm tuổi này kết hợp nhuần nhuyễn giữa ca hát, đối thoại, võ thuật và nhào lộn, với các lớp hóa trang mặt nạ (liên phổ) đặc trưng thể hiện tính cách nhân vật.'),
};
